#!/bin/bash
sed -i 's/--animate-cta-pulse: cta-pulse 2.5s ease-in-out infinite;/--animate-cta-pulse: cta-pulse 2.5s ease-in-out infinite;\n  --animate-error-shake: error-shake 3s ease-in-out infinite;/g' src/index.css
sed -i 's/  @keyframes cta-pulse {/  @keyframes error-shake {\n    0%, 80%, 100% { transform: translateX(0) scale(1); border-color: rgba(255, 255, 255, 0.1); }\n    82% { transform: translateX(-2px) scale(0.98); border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 15px rgba(239, 68, 68, 0.2); }\n    84% { transform: translateX(2px) scale(0.98); }\n    86% { transform: translateX(-2px) scale(0.98); }\n    88% { transform: translateX(2px) scale(0.98); }\n    90% { transform: translateX(0) scale(1); border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 15px rgba(239, 68, 68, 0.2); }\n  }\n  @keyframes cta-pulse {/g' src/index.css
